#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <stdint.h>

#include <cub/block/block_radix_sort.cuh>
#include <cub/block/block_scan.cuh>

#if defined(__CUDA_ARCH__)
  #define LDG(p) __ldg(p)
#else
  #define LDG(p) (*(p))
#endif

// ---------------- RNG (stateless, deterministic) ----------------
__device__ __forceinline__ uint64_t splitmix64(uint64_t x) {
  x += 0x9e3779b97f4a7c15ULL;
  uint64_t z = x;
  z = (z ^ (z >> 30)) * 0xbf58476d1ce4e5b9ULL;
  z = (z ^ (z >> 27)) * 0x94d049bb133111ebULL;
  return z ^ (z >> 31);
}
__device__ __forceinline__ float u01_float(uint64_t v) {
  return float((uint32_t)(v >> 40)) * (1.0f / 16777216.0f); // 24-bit mantissa
}

template<int BLOCK>
__device__ __forceinline__ void block_reduce_argmax(float v, int idx, float &out_v, int &out_i) {
  #pragma unroll
  for (int off = 16; off > 0; off >>= 1) {
    float ov = __shfl_down_sync(0xffffffff, v, off);
    int   oi = __shfl_down_sync(0xffffffff, idx, off);
    if (ov > v) { v = ov; idx = oi; }
  }
  __shared__ float shm_v[32];
  __shared__ int   shm_i[32];
  int lane = threadIdx.x & 31;
  int warp = threadIdx.x >> 5;
  if (lane == 0) { shm_v[warp] = v; shm_i[warp] = idx; }
  __syncthreads();
  float tv = -1e20f; int ti = 0;
  if (threadIdx.x < (BLOCK/32)) { tv = shm_v[lane]; ti = shm_i[lane]; }
  if (warp == 0) {
    #pragma unroll
    for (int off = 16; off > 0; off >>= 1) {
      float ov = __shfl_down_sync(0xffffffff, tv, off);
      int   oi = __shfl_down_sync(0xffffffff, ti, off);
      if (ov > tv) { tv = ov; ti = oi; }
    }
  }
  __syncthreads();
  if (threadIdx.x == 0) { out_v = tv; out_i = ti; }
}

__device__ __forceinline__ uint32_t float_to_key_desc(float x) {
  // Since probs are non-negative, we can sort by bitwise float ascending after invert to get descending.
  // For safety with any NaNs/negatives, use ordered-key transform.
  uint32_t u = __float_as_uint(x);
  uint32_t mask = (u & 0x80000000u) ? 0xffffffffu : 0x80000000u;
  uint32_t ordered = u ^ mask;
  return ~ordered; // descending
}

template<int BLOCK, int V>
__global__ void top_k_top_p_sampling_from_probs_v128256_kernel(
    const float* __restrict__ probs,
    const int32_t* __restrict__ top_k,
    const float* __restrict__ top_p,
    int64_t* __restrict__ samples,
    int batch_size,
    uint64_t seed)
{
  constexpr int STRIDE = V / BLOCK; // 128256/256=501
  static_assert(STRIDE * BLOCK == V, "V must be divisible by BLOCK");

  int b = (int)blockIdx.x;
  if (b >= batch_size) return;

  const float* row = probs + (size_t)b * (size_t)V;

  int k_in = (int)LDG(top_k + b);
  float p_in = LDG(top_p + b);

  int k = k_in;
  if (k < 0) k = 0;
  if (k > V) k = V;

  // p<=0 => argmax after (optional) top-k; argmax unchanged by top-k.
  if (p_in <= 0.0f) {
    float bestv = -1e20f;
    int besti = 0;
    for (int i = threadIdx.x; i < V; i += BLOCK) {
      float v = LDG(row + i);
      if (v > bestv) { bestv = v; besti = i; }
    }
    __shared__ float outv;
    __shared__ int outi;
    block_reduce_argmax<BLOCK>(bestv, besti, outv, outi);
    if (threadIdx.x == 0) samples[b] = (int64_t)outi;
    return;
  }

  // Per-thread striped storage of sorted payload (prob + idx) to avoid reload and enable correct scans.
  float vals[STRIDE];
  int   idxs[STRIDE];
  uint32_t keys[STRIDE];

  #pragma unroll
  for (int j = 0; j < STRIDE; ++j) {
    int i = j * BLOCK + threadIdx.x;
    float v = LDG(row + i);
    vals[j] = v;
    idxs[j] = i;
    keys[j] = float_to_key_desc(v);
  }

  using BlockSort = cub::BlockRadixSort<uint32_t, BLOCK, STRIDE, int>;
  __shared__ typename BlockSort::TempStorage sort_temp;
  BlockSort(sort_temp).SortBlockedToStriped(keys, idxs);

  // Reorder vals to match sorted idxs (payload not carried in sort).
  #pragma unroll
  for (int j = 0; j < STRIDE; ++j) vals[j] = LDG(row + idxs[j]);

  // Apply top-k first.
  int consider_n = (k > 0 && k < V) ? k : V;

  using BlockScan = cub::BlockScan<float, BLOCK>;
  __shared__ typename BlockScan::TempStorage scan_temp;

  // Sum of considered prefix for renorm (top-k stage).
  float partial_consider = 0.f;
  #pragma unroll
  for (int j = 0; j < STRIDE; ++j) {
    int r = j * BLOCK + threadIdx.x;
    if (r < consider_n) partial_consider += vals[j];
  }
  float dummy_ex;
  float sum_consider;
  BlockScan(scan_temp).ExclusiveSum(partial_consider, dummy_ex, sum_consider);
  __shared__ float sum_consider_sh;
  if (threadIdx.x == 0) sum_consider_sh = sum_consider;
  __syncthreads();
  sum_consider = sum_consider_sh;

  // top-p keep count (over renormalized considered prefix).
  int keep_n = consider_n;
  if (p_in < 1.0f) {
    __shared__ int keep_found;
    __shared__ int keep_value;
    __shared__ float cdf_base;
    if (threadIdx.x == 0) { keep_found = 0; keep_value = consider_n; cdf_base = 0.f; }
    __syncthreads();

    // Shared segment buffers (defined once; avoid illegal per-iteration shared declarations).
    __shared__ float sh_ex[BLOCK];
    __shared__ float sh_v[BLOCK];

    int iters = (consider_n + BLOCK - 1) / BLOCK;
    for (int it = 0; it < iters; ++it) {
      int r = it * BLOCK + threadIdx.x;
      float v = 0.f;
      if (r < consider_n) {
        float denom = (sum_consider > 0.f) ? sum_consider : 0.f;
        v = (denom > 0.f) ? (vals[it] / denom) : 0.f; // striped: rank r uses vals[it]
      }

      float ex, block_total;
      BlockScan(scan_temp).ExclusiveSum(v, ex, block_total);

      sh_ex[threadIdx.x] = ex;
      sh_v[threadIdx.x] = v;
      __syncthreads();

      if (threadIdx.x == 0 && keep_found == 0) {
        float base = cdf_base;
        for (int t = 0; t < BLOCK; ++t) {
          int rr = it * BLOCK + t;
          if (rr >= consider_n) break;
          float cdf_val = base + sh_ex[t] + sh_v[t];
          if (cdf_val > p_in) {
            keep_found = 1;
            keep_value = rr + 1; // keep through this token
            break;
          }
        }
        cdf_base = base + block_total;
      }
      __syncthreads();
      if (keep_found) break;
    }

    __shared__ int keep_n_sh;
    if (threadIdx.x == 0) {
      int kv = keep_value;
      if (kv < 1) kv = 1;
      if (kv > consider_n) kv = consider_n;
      keep_n_sh = kv;
    }
    __syncthreads();
    keep_n = keep_n_sh;
  }

  // Final kept-sum for renorm before multinomial.
  float partial_keep = 0.f;
  #pragma unroll
  for (int j = 0; j < STRIDE; ++j) {
    int r = j * BLOCK + threadIdx.x;
    if (r < keep_n) partial_keep += vals[j];
  }
  float sum_keep;
  BlockScan(scan_temp).ExclusiveSum(partial_keep, dummy_ex, sum_keep);
  __shared__ float sum_keep_sh;
  if (threadIdx.x == 0) sum_keep_sh = sum_keep;
  __syncthreads();
  sum_keep = sum_keep_sh;

  // RNG
  __shared__ float u_sh;
  if (threadIdx.x == 0) {
    uint64_t s = seed ^ ((uint64_t)(b + 1) * 0x9e3779b97f4a7c15ULL);
    u_sh = u01_float(splitmix64(s));
  }
  __syncthreads();
  float u = u_sh;

  // Multinomial selection over kept prefix.
  __shared__ int chosen_sh;
  __shared__ int found2;
  __shared__ float cdf2_base;
  if (threadIdx.x == 0) { chosen_sh = 0; found2 = 0; cdf2_base = 0.f; }
  __syncthreads();

  __shared__ float sh2_ex[BLOCK];
  __shared__ float sh2_v[BLOCK];
  __shared__ int   sh2_id[BLOCK];

  int iters2 = (keep_n + BLOCK - 1) / BLOCK;
  for (int it = 0; it < iters2; ++it) {
    int r = it * BLOCK + threadIdx.x;
    float v = 0.f;
    int id = 0;
    if (r < keep_n) {
      float denom = (sum_keep > 0.f) ? sum_keep : 0.f;
      v = (denom > 0.f) ? (vals[it] / denom) : 0.f;
      id = idxs[it];
    }

    float ex, block_total;
    BlockScan(scan_temp).ExclusiveSum(v, ex, block_total);

    sh2_ex[threadIdx.x] = ex;
    sh2_v[threadIdx.x] = v;
    sh2_id[threadIdx.x] = id;
    __syncthreads();

    if (threadIdx.x == 0 && found2 == 0) {
      float base = cdf2_base;
      int last_id = sh2_id[0];
      for (int t = 0; t < BLOCK; ++t) {
        int rr = it * BLOCK + t;
        if (rr >= keep_n) break;
        last_id = sh2_id[t];
        float cdf_val = base + sh2_ex[t] + sh2_v[t];
        if (u < cdf_val) {
          chosen_sh = sh2_id[t];
          found2 = 1;
          break;
        }
      }
      if (!found2) chosen_sh = last_id;
      cdf2_base = base + block_total;
    }
    __syncthreads();
    if (found2) break;
  }

  if (threadIdx.x == 0) samples[b] = (int64_t)chosen_sh;
}

void launch_top_k_top_p_sampling_from_probs_v128256(
    const float* probs,
    const int32_t* top_k,
    const float* top_p,
    int64_t* samples,
    int batch_size,
    uint64_t seed,
    cudaStream_t stream)
{
  constexpr int BLOCK = 256;
  dim3 grid((unsigned)batch_size);
  dim3 block(BLOCK);
  top_k_top_p_sampling_from_probs_v128256_kernel<BLOCK, VOCAB_SIZE_V128256>
      <<<grid, block, 0, stream>>>(probs, top_k, top_p, samples, batch_size, seed);
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>

#include <cstdint>
#include <string>

#include "kernel.h"

static inline void check_cuda_contig(const torch::Tensor& t, const char* name) {
  TORCH_CHECK(t.defined(), name, " must be defined");
  TORCH_CHECK(t.device().is_cuda(), name, " must be a CUDA tensor");
  TORCH_CHECK(t.is_contiguous(), name, " must be contiguous");
}

static inline void check_dtype(const torch::Tensor& t, c10::ScalarType dt, const char* name) {
  TORCH_CHECK(t.scalar_type() == dt, name, " must have dtype ", c10::toString(dt),
              " but got ", c10::toString(t.scalar_type()));
}

torch::Tensor run(torch::Tensor probs, torch::Tensor top_k, torch::Tensor top_p) {
  check_cuda_contig(probs, "probs");
  check_cuda_contig(top_k, "top_k");
  check_cuda_contig(top_p, "top_p");

  check_dtype(probs, c10::kFloat, "probs");
  check_dtype(top_k, c10::kInt, "top_k");
  check_dtype(top_p, c10::kFloat, "top_p");

  TORCH_CHECK(probs.dim() == 2, "probs must be rank-2 [batch_size, vocab_size]");
  TORCH_CHECK(top_k.dim() == 1, "top_k must be rank-1 [batch_size]");
  TORCH_CHECK(top_p.dim() == 1, "top_p must be rank-1 [batch_size]");

  const int64_t B = probs.size(0);
  const int64_t V = probs.size(1);
  TORCH_CHECK(V == VOCAB_SIZE_V128256, "vocab_size must be ", VOCAB_SIZE_V128256, " but got ", V);
  TORCH_CHECK(top_k.size(0) == B, "top_k size must match batch_size");
  TORCH_CHECK(top_p.size(0) == B, "top_p size must match batch_size");
  TORCH_CHECK(B >= 0 && B <= INT32_MAX, "batch_size out of range");

  auto samples = torch::empty({B}, torch::TensorOptions().device(probs.device()).dtype(torch::kInt64));

  const float* probs_ptr = probs.data_ptr<float>();
  const int32_t* top_k_ptr = top_k.data_ptr<int32_t>();
  const float* top_p_ptr = top_p.data_ptr<float>();
  int64_t* samples_ptr = samples.data_ptr<int64_t>();

  cudaStream_t stream = at::cuda::getDefaultCUDAStream();

  uint64_t seed = 0x1234abcd5678ef01ULL;
  seed ^= (uint64_t)(uintptr_t)probs_ptr;
  seed ^= (uint64_t)(uintptr_t)top_k_ptr;
  seed ^= (uint64_t)(uintptr_t)top_p_ptr;
  seed ^= ((uint64_t)B << 32) ^ (uint64_t)V;

  launch_top_k_top_p_sampling_from_probs_v128256(
      probs_ptr, top_k_ptr, top_p_ptr, samples_ptr, (int)B, seed, stream);

  cudaError_t err = cudaGetLastError();
  TORCH_CHECK(err == cudaSuccess, "CUDA kernel launch failed: ", cudaGetErrorString(err));

  err = cudaStreamSynchronize(stream);
  TORCH_CHECK(err == cudaSuccess, "CUDA stream synchronize failed: ", cudaGetErrorString(err));

  return samples;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "Kernel execution function");
}
